def test_strict_get_despatch_not_found_error():

    res = requests.get(f"{BASE_URL}/api/despatch/despatch-advice/this_will_never_be_an_ID_if_it_is_I_Bevyn_Daunt_will_eat_my_hat")

    assert res.json() == {
        "message": "Despatch advice this_will_never_be_an_ID_if_it_is_I_Bevyn_Daunt_will_eat_my_hat not found"
    }
    assert res.status_code == 404